const body = $input.first().json;
const topic = body.headers?.['x-shopify-topic'] || body.topic || 'unknown';
const product = body.title || body.product?.title || 'Unknown Product';
const price = body.variants?.[0]?.price || body.price || '0';
const stock = body.inventory_quantity || body.variants?.[0]?.inventory_quantity || 0;
const product_id = body.id || body.product_id || '';
const image_url = body.images?.[0]?.src || '';
const is_new = topic.includes('create');
const is_restock = topic.includes('update') && stock > 0;
return [{
  json: {
    topic, product_id, product, price, stock,
    image_url, is_new, is_restock,
    trigger_content: is_new || is_restock,
    timestamp: new Date().toISOString()
  }
}];

